// dcg.ts - DELETE /allowlist/:ruleId
return c.body(null, 204);
```

### Fix 3: Distinguish "already resolved" from "not found"
```typescript
// conflicts.ts - POST /conflicts/:id/resolve
if (conflict.resolvedAt) {
  return sendError(c, "CONFLICT_ALREADY_RESOLVED", "Conflict already resolved", 400);
}
if (!conflict) {
  return sendError(c, "CONFLICT_NOT_FOUND", "Conflict not found", 404);
}
```

